import React, { useEffect, useRef, useState } from 'react';
import QRCode from 'qrcode';

/**
 * QRLabel — renders a scannable QR code for an indoor artwork
 * and provides a print-ready label sheet via the browser print dialog.
 *
 * Props:
 *   qrCode  – the raw QR code string stored on the artwork
 *   artwork – full artwork object (title, artist, year)
 *   size    – canvas width/height in px (default 160)
 */
function QRLabel({ qrCode, artwork, size = 160 }) {
  const canvasRef = useRef(null);
  const [printing, setPrinting] = useState(false);

  // Render QR code onto the canvas whenever the code changes
  useEffect(() => {
    if (!qrCode || !canvasRef.current) return;
    QRCode.toCanvas(canvasRef.current, qrCode, {
      width: size,
      margin: 2,
      color: { dark: '#000000', light: '#ffffff' }
    }).catch(err => console.warn('QR render error:', err));
  }, [qrCode, size]);

  const handlePrint = async () => {
    if (!qrCode) return;
    setPrinting(true);
    try {
      // Generate a high-res data URL for the print sheet
      const dataUrl = await QRCode.toDataURL(qrCode, {
        width: 600,
        margin: 2,
        color: { dark: '#000000', light: '#ffffff' }
      });

      const title  = artwork?.title  || 'Artwork';
      const artist = artwork?.artist || '';
      const year   = artwork?.year   || '';
      const appUrl = window.location.origin;

      const win = window.open('', '_blank');
      if (!win) { alert('Pop-up blocked — allow pop-ups for this site to print labels.'); return; }

      win.document.write(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <title>QR Label — ${title}</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body {
      font-family: Georgia, 'Times New Roman', serif;
      display: flex;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
      background: #fff;
    }
    .label {
      text-align: center;
      padding: 32px;
      border: 1.5px solid #ddd;
      border-radius: 8px;
      max-width: 320px;
      width: 100%;
    }
    .label img {
      display: block;
      width: 200px;
      height: 200px;
      margin: 0 auto 16px;
    }
    .label h2 {
      font-size: 20px;
      font-weight: bold;
      color: #111;
      margin-bottom: 6px;
      line-height: 1.2;
    }
    .label .meta {
      font-size: 14px;
      color: #555;
      margin-bottom: 14px;
    }
    .label .divider {
      border: none;
      border-top: 1px solid #eee;
      margin: 12px auto;
      width: 60%;
    }
    .label .hint {
      font-size: 11px;
      color: #999;
      letter-spacing: 0.06em;
      text-transform: uppercase;
    }
    .label .code {
      font-family: monospace;
      font-size: 10px;
      color: #bbb;
      margin-top: 8px;
    }
    @media print {
      body { min-height: unset; }
      .label { border: none; padding: 0; }
    }
  </style>
</head>
<body>
  <div class="label">
    <img src="${dataUrl}" alt="QR code for ${title}" />
    <h2>${title}</h2>
    <p class="meta">${artist}${artist && year ? ' · ' : ''}${year}</p>
    <hr class="divider" />
    <p class="hint">Scan with the Gestalt app</p>
    <p class="code">${appUrl}</p>
  </div>
  ${'<script>'}
    window.onload = function () {
      setTimeout(function () { window.print(); }, 300);
    };
  ${'<'}/script>
</body>
</html>`);
      win.document.close();
    } catch (err) {
      console.error('Print error:', err);
    } finally {
      setPrinting(false);
    }
  };

  if (!qrCode) return null;

  return (
    <div style={styles.wrapper}>
      <canvas ref={canvasRef} style={styles.canvas} />
      <button
        type="button"
        onClick={handlePrint}
        disabled={printing}
        style={styles.printBtn}
      >
        {printing ? 'Opening…' : '🖨 Print Label'}
      </button>
    </div>
  );
}

const styles = {
  wrapper: {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'flex-start',
    gap: '8px',
    marginTop: '4px'
  },
  canvas: {
    borderRadius: '6px',
    border: '1px solid rgba(255,255,255,0.1)',
    background: '#fff',
    display: 'block'
  },
  printBtn: {
    padding: '8px 16px',
    borderRadius: '8px',
    border: '1px solid rgba(0,255,136,0.4)',
    background: 'rgba(0,255,136,0.08)',
    color: '#00ff88',
    cursor: 'pointer',
    fontSize: '13px',
    fontWeight: '500'
  }
};

export default QRLabel;
