import {
  collection,
  addDoc,
  updateDoc,
  deleteDoc,
  doc,
  getDocs,
  getDoc,
  query,
  orderBy
} from "firebase/firestore";
import { db } from './firebase';

const LOCATIONS_COLLECTION = 'locations';

function logError(label, error) {
  const code = error?.code ?? '';
  const msg  = error?.message ?? String(error);
  console.error(`${label} code="${code}" msg="${msg}"`);
}

// Get all locations
export async function getAllLocations() {
  try {
    const q = query(collection(db, LOCATIONS_COLLECTION), orderBy('city'));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(d => ({
      id: d.id,
      ...d.data()
    }));
  } catch (error) {
    logError('Error getting locations:', error);
    throw error;
  }
}

// Get single location by ID
export async function getLocation(id) {
  try {
    const docRef = doc(db, LOCATIONS_COLLECTION, id);
    const docSnap = await getDoc(docRef);
    if (docSnap.exists()) {
      return { id: docSnap.id, ...docSnap.data() };
    } else {
      throw new Error('Location not found');
    }
  } catch (error) {
    console.error('Error getting location:', error);
    throw error;
  }
}

// Add new location
export async function addLocation(locationData) {
  try {
    const docRef = await addDoc(collection(db, LOCATIONS_COLLECTION), {
      ...locationData,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    });
    return docRef.id;
  } catch (error) {
    console.error('Error adding location:', error);
    throw error;
  }
}

// Update location
export async function updateLocation(id, locationData) {
  try {
    const docRef = doc(db, LOCATIONS_COLLECTION, id);
    await updateDoc(docRef, {
      ...locationData,
      updatedAt: new Date().toISOString()
    });
  } catch (error) {
    console.error('Error updating location:', error);
    throw error;
  }
}

// Delete location
export async function deleteLocation(id) {
  try {
    await deleteDoc(doc(db, LOCATIONS_COLLECTION, id));
  } catch (error) {
    console.error('Error deleting location:', error);
    throw error;
  }
}

// Helper: format a location document into a human-readable display label
export function getLocationLabel(location) {
  if (!location) return '';
  const parts = [];
  if (location.venue?.name) parts.push(location.venue.name);
  if (location.city) parts.push(location.city);
  if (location.country) parts.push(location.country);
  return parts.join(', ');
}

// ── Duplicate detection ────────────────────────────────────────────────────
// Groups locations by city + region + country (case-insensitive).
// Returns only groups that have more than one location document.
// Each group identifies a canonical location (most artworks linked,
// tiebroken by oldest createdAt) and the duplicates to be merged into it.
export function findDuplicateLocationGroups(locations, artworks) {
  const groups = {};
  for (const loc of locations) {
    const key = [loc.city, loc.region, loc.country]
      .map(s => (s || '').toLowerCase().trim())
      .join('|');
    if (!groups[key]) groups[key] = [];
    groups[key].push(loc);
  }

  return Object.values(groups)
    .filter(locs => locs.length > 1)
    .map(locs => {
      const withCounts = locs.map(loc => ({
        ...loc,
        artworkCount: artworks.filter(a => a.location_id === loc.id).length
      }));
      // Canonical = most artworks linked; tiebreak = oldest createdAt
      withCounts.sort((a, b) => {
        if (b.artworkCount !== a.artworkCount) return b.artworkCount - a.artworkCount;
        return (a.createdAt || '') < (b.createdAt || '') ? -1 : 1;
      });
      const [canonical, ...duplicates] = withCounts;
      return {
        label: getLocationLabel(canonical),
        canonical,
        duplicates,
        totalArtworks: withCounts.reduce((sum, l) => sum + l.artworkCount, 0)
      };
    });
}

// Delete duplicate location documents after artworks have been re-pointed.
export async function mergeLocationGroup(duplicateIds) {
  await Promise.all(duplicateIds.map(id => deleteLocation(id)));
}
