import { initializeApp } from "firebase/app";
import { getAuth } from "firebase/auth";
import { initializeFirestore } from "firebase/firestore";
import { getStorage } from "firebase/storage";

const firebaseConfig = {
  apiKey: "AIzaSyAi-EeTlhYrfAG7AnJSCYIM_6fls-LPDQE",
  authDomain: "gestalt-17ce0.firebaseapp.com",
  projectId: "gestalt-17ce0",
  storageBucket: "gestalt-17ce0.firebasestorage.app",
  messagingSenderId: "599017126322",
  appId: "1:599017126322:web:6cd4e80ef80caf92f9ccab",
  measurementId: "G-9F5PQRK9ZX"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
console.log('[Firebase] app initialised — projectId:', firebaseConfig.projectId);

// Initialize services
export const auth = getAuth(app);
console.log('[Firebase] auth ready');

// Firestore transport for Capacitor WKWebView:
// experimentalForceLongPolling disables the default gRPC-WebChannel transport
// (blocked by WKWebView) and uses plain HTTPS fetch instead.
// NOTE: Firebase v12 made experimentalForceLongPolling and
// experimentalAutoDetectLongPolling mutually exclusive — only one may be set.
export const db = (() => {
  try {
    const instance = initializeFirestore(app, {
      experimentalForceLongPolling: true,
      // Silently drop undefined fields at the SDK level (belt-and-suspenders
      // alongside the clean() helper in artworkService — prevents hard crashes
      // if any caller passes undefined values we haven't caught yet).
      ignoreUndefinedProperties: true,
    });
    console.log('[Firebase] Firestore initialised OK');
    return instance;
  } catch (e) {
    console.error(`[Firebase] Firestore init FAILED code="${e?.code ?? ''}" msg="${e?.message ?? String(e)}"`);
    throw e;
  }
})();

export const storage = getStorage(app);
console.log('[Firebase] storage ready');

export default app;
