import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { getAllArtworks, deleteArtwork } from '../services/artworkService';
import { getAllLocations, deleteLocation, getLocationLabel, findDuplicateLocationGroups, mergeLocationGroup } from '../services/locationService';
import { updateArtwork } from '../services/artworkService';
import { signOutUser } from '../services/authService';
import LocationForm from './LocationForm';
import QRLabel from './QRLabel';

// ── Badge colours per artwork type / status ────────────────────────────────────
const TYPE_COLORS = {
  museum:       { bg: 'rgba(78,205,196,0.15)',  text: '#4ecdc4',  border: 'rgba(78,205,196,0.4)'  },
  street_art:   { bg: 'rgba(255,209,102,0.15)', text: '#ffd166',  border: 'rgba(255,209,102,0.4)' },
  monument:     { bg: 'rgba(6,214,160,0.15)',   text: '#06d6a0',  border: 'rgba(6,214,160,0.4)'   },
  installation: { bg: 'rgba(239,71,111,0.15)',  text: '#ef476f',  border: 'rgba(239,71,111,0.4)'  }
};

const STATUS_COLORS = {
  active:        { bg: 'rgba(0,255,136,0.12)',   text: '#00ff88', border: 'rgba(0,255,136,0.35)'   },
  unverified:    { bg: 'rgba(255,209,102,0.12)', text: '#ffd166', border: 'rgba(255,209,102,0.35)' },
  deteriorating: { bg: 'rgba(255,107,107,0.12)', text: '#ff6b6b', border: 'rgba(255,107,107,0.35)' },
  removed:       { bg: 'rgba(136,136,136,0.12)', text: '#888',    border: 'rgba(136,136,136,0.35)' }
};

function Badge({ value, colorMap }) {
  if (!value) return null;
  const c = colorMap[value] || { bg: 'rgba(255,255,255,0.08)', text: '#ccc', border: 'rgba(255,255,255,0.15)' };
  return (
    <span style={{
      display: 'inline-block', padding: '2px 8px', borderRadius: '4px',
      fontSize: '11px', fontWeight: '600', background: c.bg, color: c.text,
      border: `1px solid ${c.border}`, textTransform: 'uppercase', letterSpacing: '0.05em'
    }}>
      {value.replace('_', ' ')}
    </span>
  );
}

// ── Artwork card with image carousel, badges, location, and QR ───────────────
function ArtworkCard({ artwork, locationLabel, onEdit, onDelete }) {
  const images = artwork.imageUrls?.length
    ? artwork.imageUrls
    : artwork.imageUrl
    ? [artwork.imageUrl]
    : [];
  const [index, setIndex] = useState(0);
  const [fading, setFading] = useState(false);
  const [showQR, setShowQR] = useState(false);
  const total = images.length;

  const goTo = (next) => {
    setFading(true);
    setTimeout(() => { setIndex(next); setFading(false); }, 150);
  };
  const prev = (e) => { e.stopPropagation(); goTo((index - 1 + total) % total); };
  const next = (e) => { e.stopPropagation(); goTo((index + 1) % total); };

  return (
    <div style={cardStyles.card}>
      {total > 0 && (
        <div style={cardStyles.carousel}>
          <img
            key={index}
            src={images[index]}
            alt={`${artwork.title} ${index + 1}`}
            style={{ ...cardStyles.image, opacity: fading ? 0 : 1, transition: 'opacity 0.15s ease' }}
          />
          {total > 1 && (
            <>
              <button onClick={prev} style={{ ...cardStyles.arrow, left: '8px' }}>‹</button>
              <button onClick={next} style={{ ...cardStyles.arrow, right: '8px' }}>›</button>
              <div style={cardStyles.badge}>{index + 1} / {total}</div>
              <div style={cardStyles.dots}>
                {images.map((_, i) => (
                  <span key={i} onClick={(e) => { e.stopPropagation(); goTo(i); }}
                    style={{ ...cardStyles.dot, background: i === index ? '#00ff88' : 'rgba(255,255,255,0.3)' }} />
                ))}
              </div>
            </>
          )}
        </div>
      )}

      <div style={cardStyles.content}>
        {/* Type + Status badges */}
        {(artwork.type || artwork.status) && (
          <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap', marginBottom: '8px' }}>
            <Badge value={artwork.type}   colorMap={TYPE_COLORS} />
            <Badge value={artwork.status} colorMap={STATUS_COLORS} />
          </div>
        )}

        <h3 style={cardStyles.cardTitle}>{artwork.title}</h3>
        <p style={cardStyles.cardArtist}>{artwork.artist}</p>
        <p style={cardStyles.cardYear}>{artwork.year}</p>

        {/* Location label */}
        {locationLabel && (
          <p style={cardStyles.cardMeta}>📍 {locationLabel}</p>
        )}

        {/* Accessibility flags */}
        {(artwork.accessibility?.wheelchair_accessible || artwork.accessibility?.tactile_available) && (
          <p style={cardStyles.cardA11y}>
            {artwork.accessibility.wheelchair_accessible && '♿ '}
            {artwork.accessibility.tactile_available && '🖐 Tactile'}
          </p>
        )}

        {/* QR code (indoor) / outdoor proximity note */}
        {artwork.locationType === 'indoor' && artwork.qrCode ? (
          <div style={cardStyles.qrSection}>
            <button onClick={() => setShowQR(v => !v)} style={cardStyles.qrToggleBtn}>
              ⬛ {showQR ? 'Hide QR Code' : 'Show QR Code'}
            </button>
            {showQR && <QRLabel qrCode={artwork.qrCode} artwork={artwork} />}
          </div>
        ) : artwork.locationType === 'outdoor' ? (
          <p style={cardStyles.cardMeta}>🌿 Outdoor · {artwork.proximityRadius || 15}m radius</p>
        ) : artwork.qrCode ? (
          <p style={cardStyles.cardQR}>QR: {artwork.qrCode}</p>
        ) : null}

        <div style={cardStyles.actions}>
          <button onClick={() => onEdit(artwork)} style={cardStyles.editButton}>Edit</button>
          <button onClick={() => onDelete(artwork.id, artwork.title)} style={cardStyles.deleteButton}>Delete</button>
        </div>
      </div>
    </div>
  );
}

const cardStyles = {
  card: {
    background: 'rgba(255,255,255,0.05)', borderRadius: '12px',
    overflow: 'hidden', border: '1px solid rgba(255,255,255,0.1)'
  },
  carousel: { position: 'relative', width: '100%', height: '200px', background: '#000' },
  image: { width: '100%', height: '200px', objectFit: 'cover', display: 'block' },
  arrow: {
    position: 'absolute', top: '50%', transform: 'translateY(-50%)',
    background: 'rgba(0,0,0,0.5)', border: 'none', color: 'white',
    fontSize: '28px', width: '36px', height: '36px', borderRadius: '50%',
    cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center',
    lineHeight: 1, padding: 0
  },
  badge: {
    position: 'absolute', top: '8px', right: '8px',
    background: 'rgba(0,0,0,0.6)', color: 'white', fontSize: '11px',
    padding: '3px 8px', borderRadius: '10px'
  },
  dots: {
    position: 'absolute', bottom: '8px', left: '50%', transform: 'translateX(-50%)',
    display: 'flex', gap: '5px'
  },
  dot: { width: '7px', height: '7px', borderRadius: '50%', cursor: 'pointer' },
  content: { padding: '20px' },
  cardTitle: { color: 'white', fontSize: '20px', margin: '0 0 6px 0' },
  cardArtist: { color: '#4ecdc4', fontSize: '15px', margin: '0 0 4px 0' },
  cardYear: { color: '#888', fontSize: '14px', margin: '0 0 8px 0' },
  cardMeta: { color: '#666', fontSize: '12px', margin: '0 0 4px 0' },
  cardA11y: { color: '#555', fontSize: '12px', margin: '0 0 8px 0' },
  cardQR: { color: '#555', fontSize: '12px', fontFamily: 'monospace', margin: '0 0 12px 0' },
  qrSection: { marginBottom: '12px' },
  qrToggleBtn: {
    padding: '7px 14px', borderRadius: '8px', border: '1px solid rgba(0,255,136,0.35)',
    background: 'rgba(0,255,136,0.07)', color: '#00ff88', cursor: 'pointer',
    fontSize: '13px', marginBottom: '8px'
  },
  actions: { display: 'flex', gap: '8px', marginTop: '12px' },
  editButton: {
    flex: 1, padding: '10px', background: 'rgba(0,255,136,0.1)',
    border: '1px solid #00ff88', borderRadius: '6px', color: '#00ff88',
    cursor: 'pointer', fontSize: '14px'
  },
  deleteButton: {
    flex: 1, padding: '10px', background: 'rgba(255,107,107,0.1)',
    border: '1px solid #ff6b6b', borderRadius: '6px', color: '#ff6b6b',
    cursor: 'pointer', fontSize: '14px'
  }
};

// ── Main Dashboard ────────────────────────────────────────────────────────────
function AdminDashboard({ onEditArtwork, onAddNew }) {
  const [activeTab, setActiveTab]         = useState('artworks');
  const [artworks, setArtworks]           = useState([]);
  const [locations, setLocations]         = useState([]);
  const [loading, setLoading]             = useState(true);
  const [loadError, setLoadError]         = useState('');
  const [editingLocation, setEditingLocation]   = useState(null);
  const [showLocationForm, setShowLocationForm] = useState(false);
  const [filter, setFilter]                     = useState('all');
  const [searchInput, setSearchInput]           = useState('');
  const [searchQuery, setSearchQuery]           = useState('');
  const [visibleCount, setVisibleCount]         = useState(20);
  const [merging, setMerging]                   = useState(false);
  const [mergeStatus, setMergeStatus]           = useState('');
  const sentinelRef = useRef(null);
  const debounceRef = useRef(null);

  useEffect(() => { loadAll(); }, []);

  // Debounced search — only update the query used for filtering after 300ms of no typing
  const handleSearchChange = useCallback((e) => {
    const value = e.target.value;
    setSearchInput(value);
    clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      setSearchQuery(value);
      setVisibleCount(20);
    }, 300);
  }, []);

  // Reset visible count when filter changes
  useEffect(() => { setVisibleCount(20); }, [filter, searchQuery]);

  // Infinite scroll — load more cards when sentinel enters viewport
  useEffect(() => {
    const el = sentinelRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisibleCount(prev => prev + 20);
        }
      },
      { rootMargin: '200px' }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [activeTab, filter, searchQuery]);

  // ── Derived: location lookup map + filter options ──────────────────────────
  const locationMap = useMemo(() => {
    const map = {};
    locations.forEach(loc => { map[loc.id] = loc; });
    return map;
  }, [locations]);

  const filterOptions = useMemo(() => {
    // Collect unique museum/gallery venue names
    const VENUE_GROUP = new Set(['museum', 'gallery', 'cultural_center']);
    const museums = new Map(); // venueName → locationId
    locations.forEach(loc => {
      if (VENUE_GROUP.has(loc.venue?.type) && loc.venue?.name) {
        museums.set(loc.venue.name, loc.id);
      }
    });
    // Also catch artworks tagged as museum whose location might not have venue.type
    artworks.forEach(a => {
      if (a.type === 'museum' && a.location_id && locationMap[a.location_id]) {
        const loc = locationMap[a.location_id];
        const name = loc.venue?.name || loc.city || 'Unknown Museum';
        if (!museums.has(name)) museums.set(name, loc.id);
      }
    });

    // Collect unique cities for outdoor (non-museum) artworks
    const outdoorCities = new Set();
    artworks.forEach(a => {
      if (a.type !== 'museum') {
        const loc = a.location_id ? locationMap[a.location_id] : null;
        const city = loc?.city || a.city;
        if (city) outdoorCities.add(city);
      }
    });

    return {
      museums: [...museums.entries()].sort((a, b) => a[0].localeCompare(b[0])),
      outdoorCities: [...outdoorCities].sort()
    };
  }, [artworks, locations, locationMap]);

  // ── Filtered artworks ─────────────────────────────────────────────────────
  const filteredArtworks = useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    const bySearch = q
      ? artworks.filter(a =>
          a.title?.toLowerCase().includes(q) ||
          a.artist?.toLowerCase().includes(q)
        )
      : artworks;

    if (filter === 'all') return bySearch;

    if (filter === 'outdoor') {
      return bySearch.filter(a => a.type !== 'museum');
    }

    if (filter.startsWith('outdoor:')) {
      const city = filter.slice('outdoor:'.length);
      return bySearch.filter(a => {
        if (a.type === 'museum') return false;
        const loc = a.location_id ? locationMap[a.location_id] : null;
        return (loc?.city || a.city) === city;
      });
    }

    if (filter.startsWith('museum:')) {
      const venueName = filter.slice('museum:'.length);
      return bySearch.filter(a => {
        const loc = a.location_id ? locationMap[a.location_id] : null;
        return loc?.venue?.name === venueName;
      });
    }

    return bySearch;
  }, [artworks, filter, locationMap, searchQuery]);

  // ── Duplicate location detection ───────────────────────────────────────────
  const duplicateGroups = useMemo(
    () => findDuplicateLocationGroups(locations, artworks),
    [locations, artworks]
  );

  const handleMergeDuplicates = async () => {
    if (duplicateGroups.length === 0) return;

    const preview = duplicateGroups
      .map(g => `• ${g.label} — ${g.duplicates.length + 1} locations → 1  (${g.totalArtworks} artwork${g.totalArtworks !== 1 ? 's' : ''})`)
      .join('\n');

    if (!window.confirm(
      `Merge ${duplicateGroups.length} duplicate location group${duplicateGroups.length !== 1 ? 's' : ''}?\n\n${preview}\n\nDuplicate location documents will be deleted and all linked artworks re-pointed to the canonical location. This cannot be undone.`
    )) return;

    setMerging(true);
    setMergeStatus('');
    try {
      for (const group of duplicateGroups) {
        const canonicalId  = group.canonical.id;
        const duplicateIds = group.duplicates.map(d => d.id);

        // Re-point every artwork that references a duplicate location
        const affected = artworks.filter(a => duplicateIds.includes(a.location_id));
        await Promise.all(affected.map(a => updateArtwork(a.id, { location_id: canonicalId })));

        // Delete the duplicate location documents
        await mergeLocationGroup(duplicateIds);
      }

      setMergeStatus(`✓ Merged ${duplicateGroups.length} group${duplicateGroups.length !== 1 ? 's' : ''} successfully.`);
      await loadAll();
    } catch (err) {
      setMergeStatus(`Error during merge: ${err.message}`);
      console.error('Merge failed:', err);
    } finally {
      setMerging(false);
    }
  };

  const loadAll = async () => {
    setLoading(true);
    setLoadError('');

    // Load artworks and locations independently so a failure in one
    // does not prevent the other from displaying.
    const [artworkResult, locationResult] = await Promise.allSettled([
      getAllArtworks(),
      getAllLocations()
    ]);

    if (artworkResult.status === 'fulfilled') {
      setArtworks(artworkResult.value);
    } else {
      const r = artworkResult.reason;
      const code = r?.code ?? '';
      const msg  = r?.message ?? String(r);
      console.error(`Error loading artworks: code="${code}" msg="${msg}"`);
      setLoadError(`Could not load artworks: ${msg || 'unknown error'}. Check Firestore rules.`);
    }

    if (locationResult.status === 'fulfilled') {
      setLocations(locationResult.value);
    } else {
      const r = locationResult.reason;
      console.warn(`Could not load locations: code="${r?.code ?? ''}" msg="${r?.message ?? String(r)}"`);
    }

    setLoading(false);
  };

  // ── Artworks ───────────────────────────────────────────────────────────────
  const handleDeleteArtwork = async (id, title) => {
    if (window.confirm(`Delete "${title}"?`)) {
      try {
        await deleteArtwork(id);
        setArtworks(artworks.filter(a => a.id !== id));
      } catch {
        alert('Failed to delete artwork');
      }
    }
  };

  // ── Locations ──────────────────────────────────────────────────────────────
  const handleDeleteLocation = async (id, label) => {
    if (window.confirm(`Delete location "${label}"? Artworks linked to it will lose their location reference.`)) {
      try {
        await deleteLocation(id);
        setLocations(locations.filter(l => l.id !== id));
      } catch {
        alert('Failed to delete location');
      }
    }
  };

  const handleLocationSaved = async () => {
    setShowLocationForm(false);
    setEditingLocation(null);
    const updated = await getAllLocations();
    setLocations(updated);
  };

  // ── Sign out ───────────────────────────────────────────────────────────────
  const handleSignOut = async () => {
    try {
      await signOutUser();
      window.location.reload();
    } catch (error) {
      console.error('Error signing out:', error);
    }
  };

  // Look up location label by artwork.location_id
  const getLabel = (id) => {
    const loc = locationMap[id];
    return loc ? getLocationLabel(loc) : null;
  };

  if (loading) {
    return (
      <div style={styles.loading}><p>Loading...</p></div>
    );
  }

  return (
    <div style={styles.container}>
      {/* ── Firestore error banner ─────────────────────────────────────── */}
      {loadError && (
        <div style={styles.errorBanner}>
          <strong>⚠ Load error:</strong> {loadError}
        </div>
      )}

      {/* ── Merge status banner ────────────────────────────────────────── */}
      {mergeStatus && (
        <div style={mergeStatus.startsWith('✓') ? styles.successBanner : styles.errorBanner}>
          {mergeStatus}
          <button onClick={() => setMergeStatus('')} style={styles.bannerDismiss}>✕</button>
        </div>
      )}

      {/* ── Header ────────────────────────────────────────────────────── */}
      <header style={styles.header}>
        <div>
          <h1 style={styles.title}>Gestalt Admin</h1>
          <p style={styles.subtitle}>
            {artworks.length} artwork{artworks.length !== 1 ? 's' : ''} · {locations.length} location{locations.length !== 1 ? 's' : ''}
          </p>
        </div>
        <div style={styles.headerActions}>
          {activeTab === 'artworks' && (
            <button onClick={onAddNew} style={styles.addButton}>+ Add Artwork</button>
          )}
          {activeTab === 'locations' && (
            <>
              {duplicateGroups.length > 0 && (
                <button
                  onClick={handleMergeDuplicates}
                  disabled={merging}
                  style={styles.mergeButton}
                >
                  {merging ? 'Merging…' : `⊕ Merge Duplicates (${duplicateGroups.length})`}
                </button>
              )}
              <button onClick={() => { setEditingLocation(null); setShowLocationForm(true); }} style={styles.addButton}>
                + Add Location
              </button>
            </>
          )}
          <button onClick={handleSignOut} style={styles.signOutButton}>Sign Out</button>
        </div>
      </header>

      {/* ── Tab bar ───────────────────────────────────────────────────── */}
      <div style={styles.tabBar}>
        {['artworks', 'locations'].map(tab => (
          <button key={tab} onClick={() => setActiveTab(tab)}
            style={{ ...styles.tabBtn, ...(activeTab === tab ? styles.tabBtnActive : {}) }}>
            {tab.charAt(0).toUpperCase() + tab.slice(1)}
          </button>
        ))}
      </div>

      {/* ── Artworks tab ──────────────────────────────────────────────── */}
      {activeTab === 'artworks' && (
        artworks.length === 0 ? (
          <div style={styles.empty}>
            <p style={styles.emptyText}>No artworks yet</p>
            <button onClick={onAddNew} style={styles.emptyButton}>Add Your First Artwork</button>
          </div>
        ) : (
          <>
            {/* ── Filter bar ─────────────────────────────────────────── */}
            <div style={styles.filterBar}>
              <input
                type="text"
                placeholder="Search by title or artist…"
                value={searchInput}
                onChange={handleSearchChange}
                style={styles.searchInput}
              />
              <select
                value={filter}
                onChange={e => setFilter(e.target.value)}
                style={styles.filterSelect}
              >
                <option value="all">All Artworks</option>

                {filterOptions.museums.length > 0 && (
                  <optgroup label="Museums">
                    {filterOptions.museums.map(([name]) => (
                      <option key={name} value={`museum:${name}`}>
                        {name}
                      </option>
                    ))}
                  </optgroup>
                )}

                <optgroup label="Outdoor">
                  <option value="outdoor">All Outdoor</option>
                  {filterOptions.outdoorCities.map(city => (
                    <option key={city} value={`outdoor:${city}`}>
                      {city}
                    </option>
                  ))}
                </optgroup>
              </select>

              <span style={styles.filterCount}>
                {filteredArtworks.length === artworks.length
                  ? `${artworks.length} artwork${artworks.length !== 1 ? 's' : ''}`
                  : `${filteredArtworks.length} of ${artworks.length}`}
              </span>
            </div>

            {/* ── Grid ───────────────────────────────────────────────── */}
            {filteredArtworks.length === 0 ? (
              <div style={styles.empty}>
                <p style={styles.emptyText}>No artworks match this filter</p>
                <button onClick={() => setFilter('all')} style={styles.emptyButton}>Show All</button>
              </div>
            ) : (
              <>
                <div style={styles.grid}>
                  {filteredArtworks.slice(0, visibleCount).map(artwork => (
                    <ArtworkCard
                      key={artwork.id}
                      artwork={artwork}
                      locationLabel={artwork.location_id ? getLabel(artwork.location_id) : null}
                      onEdit={onEditArtwork}
                      onDelete={handleDeleteArtwork}
                    />
                  ))}
                </div>
                {visibleCount < filteredArtworks.length && (
                  <div ref={sentinelRef} style={styles.sentinel}>
                    Loading more…
                  </div>
                )}
              </>
            )}
          </>
        )
      )}

      {/* ── Locations tab ─────────────────────────────────────────────── */}
      {activeTab === 'locations' && (
        locations.length === 0 ? (
          <div style={styles.empty}>
            <p style={styles.emptyText}>No locations yet</p>
            <button onClick={() => { setEditingLocation(null); setShowLocationForm(true); }} style={styles.emptyButton}>
              Add Your First Location
            </button>
          </div>
        ) : (
          <div style={styles.grid}>
            {locations.map(loc => (
              <div key={loc.id} style={{ ...cardStyles.card, border: '1px solid rgba(78,205,196,0.2)' }}>
                <div style={cardStyles.content}>
                  <h3 style={{ ...cardStyles.cardTitle, color: '#4ecdc4' }}>
                    {loc.venue?.name || loc.city}
                  </h3>

                  {loc.venue?.type && (
                    <div style={{ marginBottom: '8px' }}>
                      <Badge value={loc.venue.type} colorMap={TYPE_COLORS} />
                    </div>
                  )}

                  <p style={cardStyles.cardArtist}>
                    {[loc.neighborhood, loc.city, loc.region, loc.country].filter(Boolean).join(', ')}
                  </p>

                  {loc.venue?.address && (
                    <p style={{ color: '#666', fontSize: '13px', margin: '4px 0 0' }}>{loc.venue.address}</p>
                  )}

                  {loc.coordinates && (
                    <p style={{ color: '#555', fontSize: '12px', fontFamily: 'monospace', margin: '6px 0 0' }}>
                      {loc.coordinates.lat}, {loc.coordinates.lng}
                    </p>
                  )}

                  {(() => {
                    const count = artworks.filter(a => a.location_id === loc.id).length;
                    return count > 0 ? (
                      <p style={{ color: '#00ff88', fontSize: '12px', margin: '6px 0 0' }}>
                        {count} artwork{count !== 1 ? 's' : ''} linked
                      </p>
                    ) : null;
                  })()}

                  <div style={{ ...cardStyles.actions }}>
                    <button
                      onClick={() => { setEditingLocation(loc); setShowLocationForm(true); }}
                      style={cardStyles.editButton}
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => handleDeleteLocation(loc.id, getLocationLabel(loc))}
                      style={cardStyles.deleteButton}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )
      )}

      {/* ── Location form modal ────────────────────────────────────────── */}
      {showLocationForm && (
        <LocationForm
          location={editingLocation}
          onSave={handleLocationSaved}
          onCancel={() => { setShowLocationForm(false); setEditingLocation(null); }}
        />
      )}
    </div>
  );
}

