import React, { useState, useEffect } from 'react';
import { addLocation, updateLocation } from '../services/locationService';

const VENUE_TYPES = ['museum', 'gallery', 'public_space', 'cultural_center'];

function LocationForm({ location, onSave, onCancel }) {
  const [formData, setFormData] = useState({
    country: '',
    region: '',
    city: '',
    neighborhood: '',
    coordinates: { lat: '', lng: '' },
    hasVenue: false,
    venue: {
      name: '',
      type: '',
      address: '',
      floor_plan_url: '',
      hours: '',
      accessibility_notes: ''
    }
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (location) {
      setFormData({
        country: location.country || '',
        region: location.region || '',
        city: location.city || '',
        neighborhood: location.neighborhood || '',
        coordinates: {
          lat: location.coordinates?.lat ?? '',
          lng: location.coordinates?.lng ?? ''
        },
        hasVenue: !!location.venue,
        venue: {
          name: location.venue?.name || '',
          type: location.venue?.type || '',
          address: location.venue?.address || '',
          floor_plan_url: location.venue?.floor_plan_url || '',
          hours: location.venue?.hours || '',
          accessibility_notes: location.venue?.accessibility_notes || ''
        }
      });
    }
  }, [location]);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    if (name === 'hasVenue') {
      setFormData(prev => ({ ...prev, hasVenue: checked }));
    } else if (name.startsWith('venue.')) {
      const key = name.slice(6);
      setFormData(prev => ({ ...prev, venue: { ...prev.venue, [key]: value } }));
    } else if (name === 'lat' || name === 'lng') {
      setFormData(prev => ({ ...prev, coordinates: { ...prev.coordinates, [name]: value } }));
    } else {
      setFormData(prev => ({ ...prev, [name]: type === 'checkbox' ? checked : value }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const locationData = {
        country: formData.country,
        region: formData.region,
        city: formData.city,
        neighborhood: formData.neighborhood
      };

      // Only include coordinates if both lat and lng are provided
      if (formData.coordinates.lat !== '' && formData.coordinates.lng !== '') {
        locationData.coordinates = {
          lat: parseFloat(formData.coordinates.lat),
          lng: parseFloat(formData.coordinates.lng)
        };
      }

      // Only include venue if the toggle is on and a name is provided
      if (formData.hasVenue && formData.venue.name) {
        locationData.venue = {
          name: formData.venue.name,
          type: formData.venue.type,
          address: formData.venue.address,
          floor_plan_url: formData.venue.floor_plan_url,
          hours: formData.venue.hours,
          accessibility_notes: formData.venue.accessibility_notes
        };
      }

      if (location) {
        await updateLocation(location.id, locationData);
      } else {
        await addLocation(locationData);
      }

      onSave();
    } catch (err) {
      console.error('Error saving location:', err);
      setError('Failed to save location. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.overlay}>
      <div style={styles.modal}>
        <div style={styles.header}>
          <h2 style={styles.title}>{location ? 'Edit Location' : 'Add New Location'}</h2>
          <button onClick={onCancel} style={styles.closeButton}>✕</button>
        </div>

        <form onSubmit={handleSubmit} style={styles.form}>
          {/* — Geography — */}
          <p style={styles.sectionLabel}>Geography</p>

          <div style={styles.row}>
            <div style={styles.inputGroup}>
              <label style={styles.label}>City *</label>
              <input
                type="text"
                name="city"
                value={formData.city}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.inputGroup}>
              <label style={styles.label}>Country *</label>
              <input
                type="text"
                name="country"
                value={formData.country}
                onChange={handleChange}
                style={styles.input}
                placeholder="US"
                required
              />
            </div>
          </div>

          <div style={styles.row}>
            <div style={styles.inputGroup}>
              <label style={styles.label}>Region / State</label>
              <input
                type="text"
                name="region"
                value={formData.region}
                onChange={handleChange}
                style={styles.input}
                placeholder="e.g. Pennsylvania"
              />
            </div>
            <div style={styles.inputGroup}>
              <label style={styles.label}>Neighborhood</label>
              <input
                type="text"
                name="neighborhood"
                value={formData.neighborhood}
                onChange={handleChange}
                style={styles.input}
                placeholder="e.g. Center City"
              />
            </div>
          </div>

          {/* — Coordinates — */}
          <p style={styles.sectionLabel}>Coordinates (optional)</p>
          <div style={styles.row}>
            <div style={styles.inputGroup}>
              <label style={styles.label}>Latitude</label>
              <input
                type="number"
                name="lat"
                value={formData.coordinates.lat}
                onChange={handleChange}
                style={styles.input}
                placeholder="39.9526"
                step="any"
              />
            </div>
            <div style={styles.inputGroup}>
              <label style={styles.label}>Longitude</label>
              <input
                type="number"
                name="lng"
                value={formData.coordinates.lng}
                onChange={handleChange}
                style={styles.input}
                placeholder="-75.1652"
                step="any"
              />
            </div>
          </div>

          {/* — Venue toggle — */}
          <div style={styles.checkRow}>
            <input
              type="checkbox"
              name="hasVenue"
              id="hasVenue"
              checked={formData.hasVenue}
              onChange={handleChange}
              style={styles.checkbox}
            />
            <label htmlFor="hasVenue" style={styles.checkLabel}>
              This location is a named venue (museum, gallery, etc.)
            </label>
          </div>

          {formData.hasVenue && (
            <>
              <p style={styles.sectionLabel}>Venue Details</p>

              <div style={styles.row}>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Venue Name *</label>
                  <input
                    type="text"
                    name="venue.name"
                    value={formData.venue.name}
                    onChange={handleChange}
                    style={styles.input}
                    placeholder="Philadelphia Museum of Art"
                  />
                </div>
                <div style={styles.inputGroup}>
                  <label style={styles.label}>Venue Type</label>
                  <select
                    name="venue.type"
                    value={formData.venue.type}
                    onChange={handleChange}
                    style={styles.input}
                  >
                    <option value="">Select type...</option>
                    {VENUE_TYPES.map(t => (
                      <option key={t} value={t}>{t.replace('_', ' ')}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div style={styles.inputGroup}>
                <label style={styles.label}>Address</label>
                <input
                  type="text"
                  name="venue.address"
                  value={formData.venue.address}
                  onChange={handleChange}
                  style={styles.input}
                  placeholder="2600 Benjamin Franklin Pkwy, Philadelphia, PA"
                />
              </div>

              <div style={styles.inputGroup}>
                <label style={styles.label}>Hours</label>
                <input
                  type="text"
                  name="venue.hours"
                  value={formData.venue.hours}
                  onChange={handleChange}
                  style={styles.input}
                  placeholder="Tue–Sun 10am–5pm, closed Mondays"
                />
              </div>

              <div style={styles.inputGroup}>
                <label style={styles.label}>Floor Plan URL</label>
                <input
                  type="url"
                  name="venue.floor_plan_url"
                  value={formData.venue.floor_plan_url}
                  onChange={handleChange}
                  style={styles.input}
                  placeholder="https://example.com/floorplan.png"
                />
              </div>

              <div style={styles.inputGroup}>
                <label style={styles.label}>Accessibility Notes</label>
                <textarea
                  name="venue.accessibility_notes"
                  value={formData.venue.accessibility_notes}
                  onChange={handleChange}
                  style={{ ...styles.input, minHeight: '80px', resize: 'vertical' }}
                  placeholder="Accessible entrance on east side, lifts available on all floors..."
                />
              </div>
            </>
          )}

          {error && <p style={styles.error}>{error}</p>}

          <div style={styles.actions}>
            <button type="button" onClick={onCancel} style={styles.cancelButton}>
              Cancel
            </button>
            <button type="submit" style={styles.saveButton} disabled={loading}>
              {loading ? 'Saving...' : 'Save Location'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

const styles = {
  overlay: {
    position: 'fixed',
    top: 0, left: 0, right: 0, bottom: 0,
    background: 'rgba(0,0,0,0.8)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    padding: '20px',
    zIndex: 1000
  },
  modal: {
    background: '#1a1a2e',
    borderRadius: '16px',
    maxWidth: '600px',
    width: '100%',
    maxHeight: '90vh',
    overflow: 'auto',
    border: '1px solid rgba(78,205,196,0.3)'
  },
  header: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '24px',
    borderBottom: '1px solid rgba(255,255,255,0.1)'
  },
  title: {
    color: 'white',
    fontSize: '22px',
    margin: 0
  },
  closeButton: {
    background: 'none',
    border: 'none',
    color: '#888',
    fontSize: '22px',
    cursor: 'pointer',
    padding: 0,
    width: '32px',
    height: '32px'
  },
  form: {
    padding: '24px',
    display: 'flex',
    flexDirection: 'column',
    gap: '16px'
  },
  sectionLabel: {
    color: '#4ecdc4',
    fontSize: '13px',
    fontWeight: '600',
    textTransform: 'uppercase',
    letterSpacing: '0.08em',
    margin: '8px 0 0'
  },
  row: {
    display: 'grid',
    gridTemplateColumns: '1fr 1fr',
    gap: '12px'
  },
  inputGroup: {
    display: 'flex',
    flexDirection: 'column',
    gap: '6px'
  },
  label: {
    color: '#ccc',
    fontSize: '13px',
    fontWeight: '500'
  },
  input: {
    padding: '10px 12px',
    borderRadius: '8px',
    border: '1px solid rgba(255,255,255,0.1)',
    background: 'rgba(255,255,255,0.05)',
    color: 'white',
    fontSize: '14px',
    outline: 'none',
    width: '100%',
    boxSizing: 'border-box'
  },
  checkRow: {
    display: 'flex',
    alignItems: 'center',
    gap: '10px',
    marginTop: '4px'
  },
  checkbox: {
    accentColor: '#4ecdc4',
    width: '16px',
    height: '16px',
    cursor: 'pointer',
    flexShrink: 0
  },
  checkLabel: {
    color: '#ccc',
    fontSize: '14px',
    cursor: 'pointer'
  },
  error: {
    color: '#ff6b6b',
    fontSize: '14px',
    textAlign: 'center',
    margin: 0
  },
  actions: {
    display: 'flex',
    gap: '12px',
    marginTop: '8px'
  },
  cancelButton: {
    flex: 1,
    padding: '13px',
    borderRadius: '8px',
    border: '1px solid rgba(255,255,255,0.2)',
    background: 'rgba(255,255,255,0.05)',
    color: 'white',
    cursor: 'pointer',
    fontSize: '15px'
  },
  saveButton: {
    flex: 1,
    padding: '13px',
    borderRadius: '8px',
    border: 'none',
    background: 'linear-gradient(135deg, #4ecdc4, #2eada4)',
    color: '#000',
    fontWeight: 'bold',
    cursor: 'pointer',
    fontSize: '15px'
  }
};

export default LocationForm;
