const TTS_API_KEY = process.env.REACT_APP_GOOGLE_TTS_API_KEY;
const TTS_URL = `https://texttospeech.googleapis.com/v1/text:synthesize?key=${TTS_API_KEY}`;

/**
 * Convert a base64 string to a Blob.
 */
function base64ToBlob(base64, mimeType) {
  const bytes = atob(base64);
  const arr = new Uint8Array(bytes.length);
  for (let i = 0; i < bytes.length; i++) arr[i] = bytes.charCodeAt(i);
  return new Blob([arr], { type: mimeType });
}

/**
 * Generate spoken MP3 audio from text using Google Cloud Text-to-Speech.
 * Uses the Neural2-F voice (natural-sounding US English female).
 * @param {string} text
 * @returns {Promise<Blob>} MP3 audio blob
 */
export async function generateSpeech(text) {
  if (!TTS_API_KEY) {
    throw new Error('REACT_APP_GOOGLE_TTS_API_KEY is not set. Add it to your .env file.');
  }

  if (!text?.trim()) {
    throw new Error('No text provided for audio generation.');
  }

  const response = await fetch(TTS_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      input: { text: text.trim() },
      voice: {
        languageCode: 'en-US',
        name: 'en-US-Neural2-F'   // Natural-sounding US English female voice
      },
      audioConfig: {
        audioEncoding: 'MP3',
        speakingRate: 0.9,          // Slightly slower for museum clarity
        pitch: 0.0
      }
    })
  });

  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(err?.error?.message || `Google TTS error: ${response.status}`);
  }

  const data = await response.json();
  const audioContent = data?.audioContent;
  if (!audioContent) throw new Error('No audio returned from Google TTS.');

  return base64ToBlob(audioContent, 'audio/mpeg');
}
