import {
  collection,
  addDoc,
  updateDoc,
  deleteDoc,
  doc,
  getDocs,
  getDoc,
  onSnapshot,
  query,
  orderBy
} from "firebase/firestore";
import { ref, uploadBytes, getDownloadURL } from "firebase/storage";
import { db, storage } from './firebase';

const ARTWORKS_COLLECTION = 'artworks';

// ── Firestore REST helpers ─────────────────────────────────────────────────
// The Firestore JS SDK uses HTTP long-poll (streaming) transport on iOS
// Capacitor, which WKWebView buffers indefinitely — queries never resolve.
// The Firestore REST API uses plain one-shot HTTPS GET responses that
// WKWebView handles correctly (same pattern as MobileNet model downloads).

const FIRESTORE_REST_BASE =
  'https://firestore.googleapis.com/v1/projects/gestalt-17ce0/databases/(default)/documents';

function parseRestValue(v) {
  if (!v) return null;
  if ('stringValue'    in v) return v.stringValue;
  if ('integerValue'   in v) return Number(v.integerValue);
  if ('doubleValue'    in v) return v.doubleValue;
  if ('booleanValue'   in v) return v.booleanValue;
  if ('nullValue'      in v) return null;
  if ('timestampValue' in v) return v.timestampValue;
  if ('arrayValue'     in v)
    return (v.arrayValue.values || []).map(parseRestValue);
  if ('mapValue'       in v) {
    const obj = {};
    for (const [k, val] of Object.entries(v.mapValue.fields || {}))
      obj[k] = parseRestValue(val);
    return obj;
  }
  return null;
}

function parseRestDoc(doc) {
  const id = doc.name.split('/').pop();
  const data = {};
  for (const [k, v] of Object.entries(doc.fields || {}))
    data[k] = parseRestValue(v);
  return { id, ...data };
}

// The Firebase Auth JS SDK also uses XHR internally, which WKWebView buffers
// the same way as Firestore. Bypass it entirely and use the Identity Toolkit
// REST API — a plain HTTP POST with a complete JSON response.
const FIREBASE_API_KEY = 'AIzaSyAi-EeTlhYrfAG7AnJSCYIM_6fls-LPDQE';
// Firebase ID tokens expire after 3600s. Cache the token and its expiry;
// refresh automatically when fewer than 5 minutes remain.
let _cachedAnonToken = null;
let _tokenExpiresAt  = 0; // ms epoch
const TOKEN_REFRESH_BUFFER_MS = 5 * 60 * 1000; // refresh 5 min before expiry

async function getAnonIdToken() {
  if (_cachedAnonToken && Date.now() < _tokenExpiresAt - TOKEN_REFRESH_BUFFER_MS) {
    return _cachedAnonToken;
  }
  const resp = await fetch(
    `https://identitytoolkit.googleapis.com/v1/accounts:signUp?key=${FIREBASE_API_KEY}`,
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ returnSecureToken: true }),
    }
  );
  const json = await resp.json();
  if (!resp.ok) throw new Error(`Auth REST ${resp.status}: ${json?.error?.message ?? resp.statusText}`);
  _cachedAnonToken = json.idToken;
  // expiresIn is returned as a string (e.g. "3600") — convert to ms
  _tokenExpiresAt  = Date.now() + Number(json.expiresIn ?? 3600) * 1000;
  console.log('[REST] anonymous sign-in OK, token valid for', json.expiresIn, 's');
  return _cachedAnonToken;
}

// Fetch all artworks via the Firestore REST API (not the SDK transport).
// Handles Firestore pagination automatically and returns a flat array.
export async function getAllArtworksREST() {
  let token = null;
  try {
    token = await getAnonIdToken();
  } catch (e) {
    console.warn(`[REST] auth failed (${e?.message ?? e}), trying unauthenticated`);
  }

  const headers = token ? { Authorization: `Bearer ${token}` } : {};

  const all = [];
  let pageToken;
  do {
    const url = new URL(`${FIRESTORE_REST_BASE}/${ARTWORKS_COLLECTION}`);
    url.searchParams.set('pageSize', '200');
    url.searchParams.set('orderBy', 'title');
    if (pageToken) url.searchParams.set('pageToken', pageToken);

    const resp = await fetch(url.toString(), { headers });
    if (!resp.ok) {
      const text = await resp.text().catch(() => '');
      throw new Error(`Firestore REST ${resp.status}: ${text.slice(0, 200)}`);
    }
    const json = await resp.json();
    if (json.documents) all.push(...json.documents.map(parseRestDoc));
    pageToken = json.nextPageToken;
  } while (pageToken);

  return all;
}

// Firestore rejects `undefined` values — strip them recursively before every write.
// JSON round-trip is the simplest cross-browser approach: JSON.stringify omits
// object keys whose value is undefined, then JSON.parse restores the structure.
function clean(data) {
  return JSON.parse(JSON.stringify(data));
}

// Capacitor's bridge serialises Error objects as {} because .message/.stack
// are non-enumerable. Build a single string so the native console always
// shows a readable message regardless of how it handles multi-arg calls.
function logError(label, error) {
  const code = error?.code ?? '';
  const msg  = error?.message ?? String(error);
  console.error(`${label} code="${code}" msg="${msg}"`);
}

// Get all artworks
export async function getAllArtworks() {
  try {
    const q = query(collection(db, ARTWORKS_COLLECTION), orderBy('title'));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    }));
  } catch (error) {
    logError('Error getting artworks:', error);
    throw error;
  }
}

// Get single artwork by ID
export async function getArtwork(id) {
  try {
    const docRef = doc(db, ARTWORKS_COLLECTION, id);
    const docSnap = await getDoc(docRef);
    
    if (docSnap.exists()) {
      return { id: docSnap.id, ...docSnap.data() };
    } else {
      throw new Error('Artwork not found');
    }
  } catch (error) {
    console.error('Error getting artwork:', error);
    throw error;
  }
}

// Get artwork by QR code
// Uses the REST API (not the SDK) so QR lookups work on iOS Capacitor,
// where the Firestore SDK's long-poll transport is buffered by WKWebView.
export async function getArtworkByQR(qrCode) {
  try {
    const artworks = await getAllArtworksREST();
    return artworks.find(artwork => artwork.qrCode === qrCode);
  } catch (error) {
    console.error('Error getting artwork by QR:', error);
    throw error;
  }
}

// Add new artwork
export async function addArtwork(artworkData) {
  try {
    const docRef = await addDoc(collection(db, ARTWORKS_COLLECTION), clean({
      ...artworkData,
      schema_version: '1.0',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString()
    }));
    return docRef.id;
  } catch (error) {
    console.error('Error adding artwork:', error);
    throw error;
  }
}

// Update artwork
export async function updateArtwork(id, artworkData) {
  try {
    const docRef = doc(db, ARTWORKS_COLLECTION, id);
    await updateDoc(docRef, clean({
      ...artworkData,
      schema_version: '1.0',
      updatedAt: new Date().toISOString()
    }));
  } catch (error) {
    console.error('Error updating artwork:', error);
    throw error;
  }
}

// Delete artwork
export async function deleteArtwork(id) {
  try {
    await deleteDoc(doc(db, ARTWORKS_COLLECTION, id));
  } catch (error) {
    console.error('Error deleting artwork:', error);
    throw error;
  }
}

// Upload a single image to Firebase Storage
export async function uploadArtworkImage(file, artworkId) {
  try {
    const uniqueName = `${Date.now()}_${file.name}`;
    const storageRef = ref(storage, `artworks/${artworkId}/${uniqueName}`);
    await uploadBytes(storageRef, file);
    const downloadURL = await getDownloadURL(storageRef);
    return downloadURL;
  } catch (error) {
    console.error('Error uploading image:', error);
    throw error;
  }
}

// Upload multiple reference images to Firebase Storage.
// Returns an array of download URLs in the same order as the input files.
export async function uploadArtworkImages(files, artworkId) {
  try {
    const urls = await Promise.all(
      files.map(async (file) => {
        const storageRef = ref(
          storage,
          `artworks/${artworkId}/images/${Date.now()}-${Math.random().toString(36).slice(2)}-${file.name}`
        );
        await uploadBytes(storageRef, file);
        return getDownloadURL(storageRef);
      })
    );
    return urls;
  } catch (error) {
    console.error('Error uploading images:', error);
    throw error;
  }
}

// Upload audio file to Firebase Storage
export async function uploadAudioGuide(file, artworkId) {
  try {
    const storageRef = ref(storage, `audio/${artworkId}/${file.name}`);
    await uploadBytes(storageRef, file);
    const downloadURL = await getDownloadURL(storageRef);
    return downloadURL;
  } catch (error) {
    console.error('Error uploading audio:', error);
    throw error;
  }
}

// Upload a generated audio Blob (e.g. from TTS) to Firebase Storage
export async function uploadGeneratedAudio(blob, artworkId) {
  try {
    const filename = `${Date.now()}_visual_description.mp3`;
    const storageRef = ref(storage, `audio/${artworkId}/${filename}`);
    await uploadBytes(storageRef, blob, { contentType: 'audio/mpeg' });
    const downloadURL = await getDownloadURL(storageRef);
    return downloadURL;
  } catch (error) {
    console.error('Error uploading generated audio:', error);
    throw error;
  }
}

// Generate QR code (unique ID for each artwork)
export function generateQRCode() {
  return `ART-${Date.now()}-${Math.random().toString(36).substr(2, 9).toUpperCase()}`;
}

// Stream all artworks via onSnapshot — delivers results as soon as the first
// batch arrives from Firestore rather than waiting for a full getDocs response.
// Better suited to Capacitor iOS long-poll transport which can be slow to
// deliver the first getDocs reply.
//
// Returns the unsubscribe function; call it on component unmount.
//
// onData(artworks[])  called immediately with each update
// onError(error)      called on Firestore read errors
export function streamArtworks(onData, onError) {
  const q = query(collection(db, ARTWORKS_COLLECTION), orderBy('title'));
  return onSnapshot(
    q,
    (snapshot) => {
      const artworks = snapshot.docs.map(d => ({ id: d.id, ...d.data() }));
      onData(artworks);
    },
    (error) => {
      logError('Error streaming artworks:', error);
      if (onError) onError(error);
    }
  );
}
