const GEMINI_API_KEY = process.env.REACT_APP_GEMINI_API_KEY;
const GEMINI_URL = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=${GEMINI_API_KEY}`;

const PROMPT = `You are an expert art analyst. Examine the provided artwork image(s) and write a detailed visual description of approximately 350 words. Cover:
- Subject matter and composition
- Color palette, tones, and lighting
- Texture, brushwork, or medium (if discernible)
- Perspective, depth, and spatial arrangement
- Mood or atmosphere conveyed
- Any notable visual details or focal points

Write in clear, engaging prose suitable for a museum audio guide, at a high-school reading level — avoid overly technical jargon and explain any art terms you use. Structure the description as exactly two paragraphs totaling 8–12 sentences (250–400 words). You MUST end with a complete sentence and a period — never stop mid-sentence or mid-thought. Do not speculate about the artist's intent — focus purely on what is visually present.`;

/**
 * Convert a File or Blob to { base64, mimeType }
 */
function blobToBase64(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const base64 = reader.result.split(',')[1];
      resolve({ base64, mimeType: blob.type || 'image/jpeg' });
    };
    reader.onerror = reject;
    reader.readAsDataURL(blob);
  });
}

/**
 * Build an inlineData part from a File or a URL string.
 * Returns null if the image can't be fetched (e.g. CORS).
 */
async function buildImagePart(entry) {
  try {
    if (entry.file) {
      const { base64, mimeType } = await blobToBase64(entry.file);
      return { inlineData: { data: base64, mimeType } };
    }
    if (entry.url?.trim()) {
      const response = await fetch(entry.url.trim());
      if (!response.ok) return null;
      const blob = await response.blob();
      const { base64, mimeType } = await blobToBase64(blob);
      return { inlineData: { data: base64, mimeType } };
    }
  } catch {
    // CORS or network error — skip this image
  }
  return null;
}

/**
 * Generate a visual description for the given image entries.
 * @param {Array<{url: string, file: File|null}>} imageEntries
 * @returns {Promise<string>} The generated description text
 */
export async function generateVisualDescription(imageEntries) {
  if (!GEMINI_API_KEY) {
    throw new Error('REACT_APP_GEMINI_API_KEY is not set. Add it to your .env file.');
  }

  const filled = imageEntries.filter(e => e.file || e.url?.trim());
  if (filled.length === 0) {
    throw new Error('Add at least one image before generating a description.');
  }

  // Build image parts (skip any that fail to load)
  const imageParts = (
    await Promise.all(filled.map(buildImagePart))
  ).filter(Boolean);

  if (imageParts.length === 0) {
    throw new Error('Could not load any images. Check that URLs are publicly accessible.');
  }

  const response = await fetch(GEMINI_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{
        parts: [{ text: PROMPT }, ...imageParts]
      }],
      generationConfig: {
        temperature: 0.4,
        maxOutputTokens: 2048
      }
    })
  });

  if (!response.ok) {
    const err = await response.json().catch(() => ({}));
    throw new Error(err?.error?.message || `Gemini API error: ${response.status}`);
  }

  const data = await response.json();
  let text = data?.candidates?.[0]?.content?.parts?.[0]?.text;
  if (!text) throw new Error('No description returned from Gemini.');
  text = text.trim();
  // Safety net: if the response doesn't end on sentence-ending punctuation,
  // trim back to the last complete sentence.
  if (!/[.!?]$/.test(text)) {
    const lastPeriod = text.lastIndexOf('.');
    const lastBang = text.lastIndexOf('!');
    const lastQuestion = text.lastIndexOf('?');
    const cutAt = Math.max(lastPeriod, lastBang, lastQuestion);
    if (cutAt > 0) text = text.substring(0, cutAt + 1);
  }
  return text;
}
